        errs.append("missing name"); return False
    return True
def has_age(rec, errs):
    if "age" not in rec:
        errs.append("missing age"); return False
    return True
errs, aud = [], []
assert validate({"name":"x","age":1}, [has_name, has_age], errs, aud) is True
assert errs == [] and aud == ["has_name","has_age"]

